#include <bits/stdc++.h>
using namespace std;
#define int long long
int ksm(int a,int b,int mod) {
	int e=a,x=1;
	while(b) {
		if(b&1) {
			x=(e*x)%mod;
		}
		e=(e*e)%mod;
		b/=2;
	}
	return x;
}
signed main() {
	ios::sync_with_stdio(0),cin.tie(0),cout.tie(0);
	int mod,m,k,x;
	cin>>mod>>m>>k>>x;
	cout<<((ksm(10,k,mod)%mod)*m%mod+x)%mod;
	return 0;
}
